import pymongo
from pymongo.errors import PyMongoError

def execute_server_side_javascript_query(collection_name, javascript_expression, mongodb_uri="mongodb://localhost:27017/"):
    """
    Connects to MongoDB, retrieves a collection, and executes a $where query
    using the provided JavaScript expression.

    Args:
        collection_name (str): The name of the MongoDB collection to query.
        javascript_expression (str): The JavaScript expression to use with $where.
        mongodb_uri (str): The MongoDB connection URI.

    Returns:
        list: A list of dictionaries representing the matching documents.
              Returns an empty list if no documents match or an error occurs.
    """
    client = None
    try:
        client = pymongo.MongoClient(mongodb_uri)
        db = client.get_database()  # Gets the default database if not specified in URI
        collection = db[collection_name]

        # Use $where operator for server-side JavaScript execution
        query = {"$where": javascript_expression}

        print(f"Executing query on collection '{collection_name}' with JavaScript: '{javascript_expression}'")
        results = list(collection.find(query))
        print(f"Found {len(results)} document(s).")
        return results

    except PyMongoError as e:
        print(f"MongoDB Error: {e}")
        return []
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return []
    finally:
        if client:
            client.close()

